ValidationRule.errorConditionFormula:
AND(
    NOT(ISBLANK(Phone_Number__c)),
    NOT(
        AND(
            /* Allowed characters: + digits spaces dashes brackets */
            REGEX(
                Phone_Number__c,
                "^[+0-9()\\-\\s]+$"
            ),

            /* After removing + spaces dashes brackets → must be 8–15 digits */
            REGEX(
                SUBSTITUTE(
                    SUBSTITUTE(
                        SUBSTITUTE(
                            SUBSTITUTE(
                                SUBSTITUTE(
                                    Phone_Number__c,
                                    "+", ""
                                ),
                                " ", ""
                            ),
                            "-", ""
                        ),
                        "(", ""
                    ),
                    ")", ""
                ),
                "^[0-9]{8,15}$"
            )
        )
    )
)
